import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // === Simplest cases ===
  it.todo("empty item list → premium 5 G (only the processing fee)");

  // === Base premiums per item type ===
  it.todo("single plain sword → 105 G (100 base + 5 fee)");
  it.todo("single plain amulet → 65 G (60 base + 5 fee)");
  it.todo("single plain staff → 85 G (80 base + 5 fee)");
  it.todo("single plain potion → 45 G (40 base + 5 fee)");

  // === Components and blocks ===
  it.todo("single rune → 30 G (25 base + 5 fee)");
  it.todo("2 runes → 55 G base premium (50 + 5 fee)");
  it.todo("3 runes → 65 G (block of 3 = 60 G base + 5 fee)");
  it.todo("4 runes → 105 G (no block; 4×25 = 100 + 5 fee)");
  it.todo("7 runes → 180 G (175 base + 5 fee)");
  it.todo("2 runes + 1 moonstone → 80 G (75 base + 5 fee, no block: different types)");
  it.todo("3 runes + 3 moonstones → 125 G (two separate blocks: 60+60 = 120 + 5 fee)");

  // === Item-specific modifiers ===
  it.todo("cursed sword → 100 base + 50 curse + 5 fee = 155 G");
  it.todo("highly enchanted sword (enchantment 5) → 100 + 30 + 5 = 135 G");
  it.todo("sword with enchantment 4 → no high-enchantment surcharge, 105 G");
  it.todo("sword with enchantment 5 AND cursed → both surcharges apply (100 + 50 + 30 + 5 = 185 G)");

  // === Customer-wide modifiers ===
  it.todo("customer with exactly 2 years → loyalty discount applies (sword: 100 - 20 + 10 first + 5 = 95 G)");
  it.todo("first insurance → 10% initial assessment surcharge (sword: 100 + 10 + 5 = 115 G for newcomer)");
  it.todo("follow-up contract → 15% discount on each contract after first");

  // === Modifier scope on multi-item policies ===
  it.todo("cursed sword + plain amulet → 100+60 = 160 base; curse adds 50 (on sword only); 160+50+10(first)+5 = 225 G");

  // === Rounding in MHPCO favor ===
  it.todo("premium calculation yielding 197.5 → 198 G (rounded up)");
  it.todo("payout calculation yielding 350.5 → 350 G (rounded down)");

  // === Integration examples ===
  it.todo("newcomer with cursed sword (steel, ench 3), 0 years → 165 G");
  it.todo("long-standing customer's second contract: cursed sword ench 7, 3 years → 160 G");
  it.todo("first insurance surcharge applies per item even for follow-up contract");

  // === Claim - basic ===
  it.todo("standard sword damage 500 → payout 400 (full minus 100 deductible)");
  it.todo("damage to rune (250 G value), damage 200 → payout 100");
  it.todo("high enchantment item (ench 8), damage 1000 → 50% then deductible = 400");
  it.todo("dragon material sword full reimbursement, damage 800, ench 5 → 700");
  it.todo("dragon material + high ench (ench 9), damage 1000 → 50% wins, then deductible = 400");
  it.todo("dragon-material sword ench exactly 8 damage 1000 → 400 (high-ench applies first)");
  it.todo("steel sword ench 9 damage 1000 → 50% then -100 = 400");

  // === Deductible per damage event ===
  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 (deductible per item)");

  // === Multiple items of same type ===
  it.todo("policy covers two swords → insurance sum 2000, cap 4000");
  it.todo("two swords both damaged → each treated separately with own deductible");
  it.todo("damages contain more entries of a type than insured → claim rejected (CLI non-zero)");

  // === Cap exhaustion ===
  it.todo("sword + amulet policy → insurance sum 1600, cap 3200");
  it.todo("cursed sword (premium modifiers don't affect cap) → cap based on unmodified insurance value 2000");
  it.todo("sword + 3 runes block → insurance sum 1750 (block doesn't affect insurance sum)");
  it.todo("sword cap 2000, two claims 1500 each → first 1400, second capped to 600");
  it.todo("remainingCap reaches 0 after exhausting cap");

  // === Edge cases / errors ===
  it.todo("quote with unknown item type → CLI non-zero exit, error to stderr");
  it.todo("claim references item not in policy → CLI non-zero exit");
  it.todo("claim with negative damage amount → CLI non-zero exit");

  // === CLI / scenario integration ===
  it.todo("full scenario with quote then claim returns results in order");
});

