  const firstInsuranceSurcharge = step.items.reduce(
    (sum, item) => sum + itemBasePremium(item) * 0.1,
    0,
  );
  const total = itemsBase + firstInsuranceSurcharge + PROCESSING_FEE;
  return { premium: Math.ceil(total) };
};

export const runScenario = (scenario: Scenario): { results: Array<QuoteResult> } => {
  return { results: scenario.steps.map(quoteStep) };
};

