type Item = {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
};
type Step = { op: "quote"; items: Array<Item> };
type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: Array<Step>;
};
type QuoteResult = { premium: number };

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PREMIUM = 60;
const COMPONENT_BASE_PREMIUM = 25;

const MAIN_ITEM_BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

const componentsBasePremium = (items: Array<Item>): number => {
  const counts: Record<string, number> = {};
  for (const item of items) counts[item.type] = (counts[item.type] ?? 0) + 1;
  let total = 0;
  for (const type of Object.keys(counts)) {
    const n = counts[type];
    const blocks = Math.floor(n / COMPONENT_BLOCK_SIZE);
    const singles = n % COMPONENT_BLOCK_SIZE;
    total += blocks * COMPONENT_BLOCK_PREMIUM + singles * COMPONENT_BASE_PREMIUM;
  }
  return total;
};

const itemsBasePremium = (items: Array<Item>): number => {
  const components = items.filter(isComponent);
  const mainItems = items.filter((i) => !isComponent(i));
  const mainsTotal = mainItems.reduce(
    (sum, item) => sum + MAIN_ITEM_BASE_PREMIUM[item.type],
    0,
  );
  return mainsTotal + componentsBasePremium(components);
};

const quoteStep = (step: Step): QuoteResult => {
  const base = itemsBasePremium(step.items);
  const firstInsurance = base * FIRST_INSURANCE_RATE;
  const total = base + firstInsurance + PROCESSING_FEE;
  return { premium: Math.ceil(total) };
};

export const runScenario = (scenario: Scenario): { results: Array<QuoteResult> } => {
