type Item = {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
};
type Step = { op: "quote"; items: Array<Item> };
type Scenario = {
  customer: { yearsWithMHPCO: number };
  steps: Array<Step>;
};
type QuoteResult = { premium: number };

const PROCESSING_FEE = 5;

const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const itemBasePremium = (item: Item): number => BASE_PREMIUM[item.type];

const quoteStep = (step: Step): QuoteResult => {
  const itemsBase = step.items.reduce((sum, item) => sum + itemBasePremium(item), 0);
  // Per-item first-insurance surcharge (10%): each item in a quote is a first insurance.
  const firstInsuranceSurcharge = step.items.reduce(
    (sum, item) => sum + itemBasePremium(item) * 0.1,
    0,
  );
  const total = itemsBase + firstInsuranceSurcharge + PROCESSING_FEE;
  return { premium: Math.ceil(total) };
};

export const runScenario = (scenario: Scenario): { results: Array<QuoteResult> } => {
  return { results: scenario.steps.map(quoteStep) };
};

